class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        int left = 0, right = 1e5;
        while (left < right) {
            int mid = left + (right - left) / 2;
            int sum = 0;
            for (int num : arr) {
                sum += min(num, mid);
            }
            if (sum < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        int res = left;
        int sum1 = 0, sum2 = 0;
        for (int num : arr) {
            sum1 += min(num, res);
            sum2 += min(num, res - 1);
        }
        return abs(target - sum1) <= abs(target - sum2) ? res : res - 1;
    }
};
```
